    def counting_sort(arr):
        size = len(arr)
        output = [0] * size
        max_val = max(arr) + 1
        count = [0] * max_val
        for i in range(0, size):
            count[arr[i]] += 1
        for i in range(1, len(count)):
            count[i] += count[i - 1]
        i = size - 1
        while i >= 0:
            output[count[arr[i]] - 1] = arr[i]
            count[arr[i]] -= 1
            i -= 1
        for i in range(0, size):
            arr[i] = output[i]

    arr = [4, 2, 2, 8, 3, 3, 1]

    counting_sort(arr)

    print('Sorted array is:', arr)

