    def radix_sort(arr):
        print('Original array:', arr)
        radixArray = [[] for _ in range(10)]
        maxVal = max(arr)
        exp = 1
        while maxVal // exp > 0:
            while len(arr) > 0:
                val = arr.pop()
                radixIndex = val // exp % 10
                radixArray[radixIndex].append(val)
            for bucket in radixArray:
                while len(bucket) > 0:
                    val = bucket.pop(0)
                    arr.append(val)
            exp *= 10
        print('Sorted array:', arr)

    arr = [170, 45, 75, 90, 802, 24, 2, 66]

